package com.agrios.platform.inventory.api;
import com.agrios.platform.common.web.TenantContextResolver; import com.agrios.platform.inventory.application.InventoryService; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import java.time.LocalDate; import java.util.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1") public class InventoryController {private final InventoryService service;private final TenantContextResolver tenants;public InventoryController(InventoryService s,TenantContextResolver t){service=s;tenants=t;}
 @PostMapping("/inventory/items") InventoryDtos.ItemResponse create(@Valid @RequestBody InventoryDtos.CreateItemRequest b,HttpServletRequest r){return service.create(tenants.resolve(r).tenantId(),actor(),b);} @PostMapping("/inventory/items/{id}/receipts") InventoryDtos.LotResponse receive(@PathVariable UUID id,@Valid @RequestBody InventoryDtos.ReceiveRequest b,HttpServletRequest r){return service.receive(tenants.resolve(r).tenantId(),actor(),id,b);} @PostMapping("/inventory/items/{id}/adjustments") InventoryDtos.ItemResponse adjust(@PathVariable UUID id,@Valid @RequestBody InventoryDtos.AdjustRequest b,HttpServletRequest r){return service.adjust(tenants.resolve(r).tenantId(),actor(),id,b);} @GetMapping("/farms/{farmId}/inventory") List<InventoryDtos.ItemResponse> list(@PathVariable UUID farmId,HttpServletRequest r){return service.list(tenants.resolve(r).tenantId(),farmId);} @GetMapping("/inventory/lots/expiring") List<InventoryDtos.LotResponse> expiring(@RequestParam LocalDate from,@RequestParam LocalDate to,HttpServletRequest r){return service.expiring(tenants.resolve(r).tenantId(),from,to);} private UUID actor(){return UUID.nameUUIDFromBytes("development-actor".getBytes());}}
